import threading
import time
import logging
from smartcard.CardMonitoring import CardMonitor, CardObserver
from smartcard.util import toHexString

logger = logging.getLogger("uvicorn")

class NFCReader(CardObserver):
    def __init__(self, on_tag_detected):
        self.on_tag_detected = on_tag_detected
        self.monitor = None
        self.is_running = False

    def start(self):
        if self.is_running:
            return
        try:
            self.monitor = CardMonitor()
            self.monitor.addObserver(self)
            self.is_running = True
            logger.info("NFC Reader (PC/SC) started")
        except Exception as e:
            logger.error(f"Failed to start NFC Reader: {e}")

    def stop(self):
        if self.monitor:
            self.monitor.deleteObserver(self)
            self.monitor = None
        self.is_running = False
        logger.info("NFC Reader stopped")

    def update(self, observable, actions):
        (addedcards, removedcards) = actions
        for card in addedcards:
            try:
                card.connection = card.createConnection()
                card.connection.connect()

                # Get UID/IDm (Standard Get Data command)
                apdu = [0xFF, 0xCA, 0x00, 0x00, 0x00]
                response, sw1, sw2 = card.connection.transmit(apdu)

                if sw1 == 0x90 and sw2 == 0x00:
                    uid = toHexString(response).replace(' ', '')
                    logger.info(f"Tag detected: {uid}")
                    self.on_tag_detected(uid)
                else:
                    logger.warning(f"Tag detected but failed to get UID (SW: {hex(sw1)} {hex(sw2)})")

            except Exception as e:
                logger.error(f"Error processing tag: {e}")

const { app, BrowserWindow } = require('electron');
const path = require('path');

function createWindow() {
    const mainWindow = new BrowserWindow({
        width: 1200,
        height: 800,
        webPreferences: {
            nodeIntegration: false,
            contextIsolation: true,
            preload: path.join(__dirname, 'renderer.js') // Using renderer.js as preload or just script
        }
    });

    mainWindow.loadFile('index.html');
    // mainWindow.webContents.openDevTools();
}

app.whenReady().then(() => {
    createWindow();

    app.on('activate', function () {
        if (BrowserWindow.getAllWindows().length === 0) createWindow();
    });
});

app.on('window-all-closed', function () {
    if (process.platform !== 'darwin') app.quit();
});

let socket;
let currentMode = 'read'; // 'read' or 'write'
let isScanningForWrite = false;

// WebSocket Connection
function connectWebSocket() {
    socket = new WebSocket('ws://localhost:8000/ws');

    socket.onopen = function(e) {
        console.log("Connected to WebSocket");
    };

    socket.onmessage = function(event) {
        const data = JSON.parse(event.data);
        if (data.type === 'nfc_detected') {
            handleNfcDetected(data.idm);
        }
    };

    socket.onclose = function(event) {
        console.log('Socket closed. Reconnecting...', event.reason);
        setTimeout(connectWebSocket, 1000);
    };

    socket.onerror = function(error) {
        console.error('Socket error:', error);
    };
}

connectWebSocket();

// Tab Switching
function openTab(mode) {
    currentMode = mode;

    // UI Update
    document.querySelectorAll('.tab-content').forEach(el => el.classList.remove('active'));
    document.querySelectorAll('.tab-btn').forEach(el => el.classList.remove('active'));

    document.getElementById(mode).classList.add('active');
    document.querySelector(`.tab-btn[onclick="openTab('${mode}')"]`).classList.add('active');

    if (mode === 'read') {
        resetRead();
    }
}

// Read Mode Logic
function resetRead() {
    document.getElementById('read-status').style.display = 'block';
    document.getElementById('read-result').style.display = 'none';
}

function handleNfcDetected(idm) {
    console.log("NFC Detected:", idm);

    if (currentMode === 'read') {
        // In read mode, just show success
        document.getElementById('read-status').style.display = 'none';
        document.getElementById('read-result').style.display = 'block';
        document.getElementById('resident-info').innerHTML = `<p>IDm: ${idm}</p><p>受付日時: ${new Date().toLocaleString()}</p>`;

        // Optionally fetch resident info from API
        fetchResidentInfo(idm);

    } else if (currentMode === 'write' && isScanningForWrite) {
        // In write mode, proceed with registration
        submitRegistration(idm);
    }
}

// Write Mode Logic
function startRegistration() {
    const form = document.getElementById('register-form');
    if (!form.checkValidity()) {
        form.reportValidity();
        return;
    }

    isScanningForWrite = true;
    document.getElementById('scan-overlay').style.display = 'flex';
}

function cancelScan() {
    isScanningForWrite = false;
    document.getElementById('scan-overlay').style.display = 'none';
}

async function submitRegistration(idm) {
    const form = document.getElementById('register-form');
    const formData = new FormData(form);
    const data = Object.fromEntries(formData.entries());

    // Add IDm and timestamp
    data.idm = idm;
    data.registered_at = new Date().toISOString();

    // Handle checkboxes (HTML forms don't send unchecked boxes, so we might need to default them)
    // For this simple implementation, we assume presence = checked
    // Map checkboxes to 0/1 or true/false
    const checkboxes = ['agree_info', 'agree_board', 'care_needed'];
    checkboxes.forEach(key => {
        data[key] = data[key] === 'on' ? 1 : 0;
    });

    // Vulnerabilities
    data.vulnerabilities = {
        eld: formData.get('vul_eld') === 'on' ? 1 : 0,
        inf: formData.get('vul_inf') === 'on' ? 1 : 0,
        prg: formData.get('vul_prg') === 'on' ? 1 : 0,
        dis: formData.get('vul_dis') === 'on' ? 1 : 0,
        for: formData.get('vul_for') === 'on' ? 1 : 0
    };
    // Remove individual vul fields from top level
    ['vul_eld', 'vul_inf', 'vul_prg', 'vul_dis', 'vul_for'].forEach(k => delete data[k]);

    try {
        const response = await fetch('http://localhost:8000/api/checkin', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(data)
        });

        if (response.ok) {
            alert('登録完了しました！');
            form.reset();
            cancelScan();
            // Switch to read mode or stay?
        } else {
            const errorText = await response.text();
            alert('登録エラー: ' + errorText);
            cancelScan();
        }
    } catch (error) {
        console.error('Registration error:', error);
        alert('通信エラーが発生しました');
        cancelScan();
    }
}

async function fetchResidentInfo(idm) {
    // Ideally we would have an endpoint GET /api/residents/{idm}
    // For now, we just skip or implement if needed.
}

